module RefModule(clk, rst_n, resume, halt, en);input clk, rst_n, resume, halt;
    output reg en;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, negedge rst_n or posedge dbg_halt) begin
        if (!rst_n)
            en = 1'b1;
        else if (resume)
            en = 1'b1;
        else if (halt)
            en = 1'b0;
    end
endmodule
